// // This module performs a 2-input OR operation on inputs a and b, and a separate 2-input OR operation on inputs c and d. The outputs of these two OR operations are then combined using a 2-input AND operation to produce an output (out). Additionally, the circuit provides a complementary output (out_n) which represents the logical negation of the combined result (out).
module top_module(
    input a,
    input b,
    input c,
    input d,
    output out,
    output out_n   );wire in1,in2;
    assign in1 = a & b;
    assign in2 = c & d;
    assign out = in1 | in2;
    assign out_n = ~(in1 | in2);


endmodule
